// AUTO-GENERATED by scripts/apply-config.mjs — edit public/calendar.template.html, not this file.

    const _CAL = window.BIRTHDAY_CONFIG?.strings?.calendar || {};
    const WEEKDAYS_ES_LONG  = (_CAL.weekdaysLong  || 'Sunday,Monday,Tuesday,Wednesday,Thursday,Friday,Saturday').split(',');
    const WEEKDAYS_ES_SHORT = (_CAL.weekdaysShort || 'Sun,Mon,Tue,Wed,Thu,Fri,Sat').split(',');
    const MONTHS_ES_SHORT   = (_CAL.monthsShort   || 'Jan,Feb,Mar,Apr,May,Jun,Jul,Aug,Sep,Oct,Nov,Dec').split(',');

    // The "now" used by the page. The DESIGN_SPEC project has currentDate 2026-05-20.
    // We honor whatever today actually is — if it's before the week, all events are future.
    const NOW = new Date();
    NOW.setHours(0,0,0,0);

    function dateAt(dateStr) {
      // Local-noon parse so we sit in the middle of the day regardless of TZ.
      return new Date(dateStr + 'T12:00:00');
    }

    function daysBetween(dateStrA, ref) {
      const a = dateAt(dateStrA);
      a.setHours(0,0,0,0);
      return Math.round((a - ref) / (1000 * 60 * 60 * 24));
    }

    function formatTimeRange(start, end) {
      if (!end) return start;
      return `${start}<span class="sep">→</span>${end}`;
    }

    function distancePhrase(days) {
      const C = window.BIRTHDAY_CONFIG?.strings?.calendar || {};
      if (days < 0) {
        const abs = Math.abs(days);
        return `${abs} ${abs === 1 ? (C.distancePastDaySuffix || 'day ago') : (C.distancePastSuffix || 'days ago')}`;
      }
      if (days === 0) return C.distanceToday || 'today';
      if (days === 1) return C.distanceTomorrow || 'tomorrow';
      if (days < 7) return `${C.distanceNextDaysPrefix || 'in'} ${days} ${C.distanceNextDaysSuffix || 'days'}`;
      if (days < 14) return `${C.distanceNextDaysPrefix || 'in'} 1 ${C.distanceWeekSuffix || 'week'}`;
      return `${C.distanceWeeksPrefix || 'in'} ${days} ${C.distanceWeeksSuffix || 'days'}`;
    }

    function escapeHtml(s) {
      if (s === null || s === undefined) return '';
      return String(s)
        .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
    }

    function renderEventCard(event, guestCode) {
      const isPrivate = event.visibility === 'private';
      // /api/guest already resolves personalNotes[code] → personalNote for this guest
      // and strips the full map. Falls back to the old shape just in case.
      const personalNote = event.personalNote || event.personalNotes?.[guestCode];
      const dressChip = event.dressCode
        ? `<div class="dress">${escapeHtml(event.dressCode)}</div>`
        : '';
      const noteHtml = personalNote
        ? `<p class="note">${escapeHtml(personalNote)}</p>`
        : '';
      const badge = isPrivate
        ? `<div class="badge">${(window.BIRTHDAY_CONFIG?.strings?.calendar?.privateBadge || 'For you')}</div>`
        : '';
      const locHtml = event.mapsUrl
        ? `<a href="${escapeHtml(event.mapsUrl)}" target="_blank" rel="noreferrer">${escapeHtml(event.location)}</a>`
        : escapeHtml(event.location);

      return `<article class="card ${isPrivate ? 'private' : ''}">
        <span class="stripe"></span>
        ${badge}
        <h3>${escapeHtml(event.title)}</h3>
        <div class="meta">
          <span class="meta-item time">${formatTimeRange(event.time, event.endTime)}</span>
          <span class="meta-item"><span class="dot"></span>${locHtml}</span>
          ${typeof event.attendees === 'number'
            ? `<span class="meta-item">${event.attendees} ${event.attendees === 1 ? (window.BIRTHDAY_CONFIG?.strings?.calendar?.personSingular || 'person') : (window.BIRTHDAY_CONFIG?.strings?.calendar?.personPlural || 'people')}</span>`
            : ''}
        </div>
        <p class="desc">${escapeHtml(event.description)}</p>
        ${noteHtml}
        ${dressChip}
      </article>`;
    }

    function renderDayGroup(dateStr, events, guestCode, index, daysFromNow) {
      const d = dateAt(dateStr);
      const num = String(d.getDate()).padStart(2, '0');
      const weekday = WEEKDAYS_ES_LONG[d.getDay()];
      const month = MONTHS_ES_SHORT[d.getMonth()];
      const fade = Math.min(7, Math.max(1, index + 1));
      const hasPrivate = events.some(e => e.visibility === 'private');
      const distLabel = distancePhrase(daysFromNow);

      const revealClass = index < 7 ? `reveal reveal-${Math.min(7, index + 6)}` : '';

      return `<div class="day ${hasPrivate ? 'private' : ''} ${revealClass}" data-fade="${fade}">
        <span class="pillar" aria-hidden="true"></span>
        <div class="date">
          <span class="num">${num}</span>
          <span class="weekday">${weekday}</span>
          <span class="month">${month}</span>
          <span class="distance">${escapeHtml(distLabel)}</span>
        </div>
        <div class="events">
          ${events.map(e => renderEventCard(e, guestCode)).join('')}
        </div>
      </div>`;
    }

    function renderThreshold(text, marker) {
      return `<div class="threshold reveal reveal-6">
        <span class="marker">${escapeHtml(marker)}</span>
        <span class="heading">${escapeHtml(text)}</span>
      </div>`;
    }

    function buildTimeline(events, guestCode) {
      // /api/guest has already filtered to this guest's visible set, so
      // every event passed in is visible.
      const visible = [...events].sort((a, b) => a.date.localeCompare(b.date));

      // Group by date
      const byDate = {};
      visible.forEach(e => {
        (byDate[e.date] = byDate[e.date] || []).push(e);
      });
      const dates = Object.keys(byDate).sort();

      // Build with a "Later in the week" threshold inserted partway:
      // place it AFTER the first ~⅓ of distinct dates (or after the 2nd day, whichever is larger).
      const splitIdx = Math.max(2, Math.ceil(dates.length / 3));

      let html = '';
      dates.forEach((dateStr, i) => {
        if (i === splitIdx) {
          const remainingDays = daysBetween(dates[i], NOW);
          const C = window.BIRTHDAY_CONFIG?.strings?.calendar || {};
          const marker = remainingDays > 0
            ? `${C.thresholdMarkerPrefix || '+'} ${remainingDays} ${C.thresholdMarkerSuffix || 'days'}`
            : (C.thresholdMarkerNone || '—');
          html += renderThreshold(C.thresholdHeading || 'Later in the week', marker);
        }
        const daysFromNow = daysBetween(dateStr, NOW);
        html += renderDayGroup(dateStr, byDate[dateStr], guestCode, i, daysFromNow);
      });

      return { html, visibleCount: visible.length, total: events.length };
    }

    function renderTodayStamp() {
      const num = document.getElementById('today-num');
      const month = document.getElementById('today-month');
      const d = new Date();
      num.textContent = String(d.getDate()).padStart(2, '0');
      const weekday = WEEKDAYS_ES_SHORT[d.getDay()];
      const mo = MONTHS_ES_SHORT[d.getMonth()];
      month.innerHTML = `${weekday} · ${mo}`;
    }

    async function load() {
      const params = new URLSearchParams(window.location.search);
      const guestCode = params.get('code');

      renderTodayStamp();

      const backLink = document.getElementById('back-link');
      if (backLink && guestCode) backLink.href = `/?code=${encodeURIComponent(guestCode)}`;

      const showError = (msg) => {
        document.getElementById('timeline').innerHTML =
          `<p style="font-family:var(--serif);font-style:italic;color:var(--soft);
            text-align:center;padding:3rem 1rem;">${msg}</p>`;
      };

      if (!guestCode) {
        const _C = window.BIRTHDAY_CONFIG?.strings?.calendar || {};
        showError(`${_C.noCodeErrorPrefix || "This link doesn't know you. Ask"} ${window.BIRTHDAY_CONFIG?.host?.name || 'the host'} ${_C.noCodeErrorSuffix || 'for yours.'}`);
        return;
      }

      let data;
      try {
        const res = await fetch(`/api/guest?code=${encodeURIComponent(guestCode)}`, { cache: 'no-store' });
        if (!res.ok) throw new Error(`fetch failed: ${res.status}`);
        data = await res.json();
      } catch (err) {
        const _C = window.BIRTHDAY_CONFIG?.strings?.calendar || {};
        showError(`${_C.noCodeErrorPrefix || "This link doesn't know you. Ask"} ${window.BIRTHDAY_CONFIG?.host?.name || 'the host'} ${_C.noCodeErrorSuffix || 'for yours.'}`);
        return;
      }

      // /api/guest already filters private events by allowedCodes and strips
      // the allowedCodes field, so visibility-gating in buildTimeline is a no-op
      // here — every returned event is visible to this guest.
      const events = data.events || [];
      if (!events.length) return;

      const firstDate = events.map(e => e.date).sort()[0];
      const start = dateAt(firstDate);
      start.setHours(0,0,0,0);

      const days = Math.max(0, Math.round((start - NOW) / (1000 * 60 * 60 * 24)));
      document.getElementById('countdown').textContent = days;

      const { html, visibleCount } = buildTimeline(events, guestCode);
      document.getElementById('timeline').innerHTML = html;

      // forYou is set by /api/guest for private events the guest is invited to.
      const privateCount = events.filter(e => e.forYou).length;
      const _CS = window.BIRTHDAY_CONFIG?.strings?.calendar || {};
      const summary = privateCount > 0
        ? `${visibleCount} ${_CS.momentsLabel || 'moments'} · ${privateCount} ${_CS.momentsForYou || 'for you'}`
        : `${visibleCount} ${_CS.momentsLabel || 'moments'}`;
      document.getElementById('event-summary').textContent = summary;
    }

    load();
  